async (page) => {
  await page.evaluate(() => window.__navCancel());
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/live_screen.png', type: 'png' }).catch(() => {});
  const s = await page.evaluate(() => {
    const g = window.__latestGameState;
    return JSON.stringify({
      pos: g.player_position,
      hp: g.player_stats.hp,
      max_hp: g.player_stats.max_hp,
      current_target: g.current_target,
      last_combat: g.last_combat,
      nearby_mobs: g.nearby_entities.filter(e => e.type === 3).slice(0, 5).map(e => ({name: e.name, dist: e.distance, hp: e.hp})),
      chat: g.ui_state.recent_chat.slice(0, 3)
    });
  });
  return s;
}
